// eslint-disable-next-line import/no-unresolved
const { Logger } = require('@meli/logger');
// eslint-disable-next-line import/no-unresolved
const env = require('frontend-env');
const { RETRY_COUNT_HEADER } = require('./constants/headers');

const logger = new Logger('restclient');

const MAX_DATA_CHARACTERS = 8000;

function logError(error) {
  const tags = {};

  if (error.config) {
    tags.method = error.config.method;
    tags.url = error.config.url;
    tags.timeout = error.config.timeout;

    if (error.config.retry) {
      // We'll only log this if there's actually a retry attempt (not the first op call)
      if (error.config.headers?.[RETRY_COUNT_HEADER] > Number.parseInt(0, 10)) {
        tags.retryAttempt = error.config.headers[RETRY_COUNT_HEADER];
      }

      tags.maxRetries = error.config.retry.maxRetries;
    }
  }

  // Errors with a response
  if (error.response) {
    if (error.response.status < 500 && !env.DEVELOPMENT) {
      return;
    }
    tags.statusCode = error.response.status;
    tags.statusText = error.response.statusText;

    if (error.response.data) {
      let responseData;

      if (error.config.responseType === 'json') {
        responseData = JSON.stringify(error.response.data);
      } else if (error.config.responseType === 'text') {
        responseData = error.response.data;
      }

      if (responseData) {
        tags.responseData = responseData.substring(0, MAX_DATA_CHARACTERS);
      }
    }
    // Errors without a response.
  } else {
    tags.statusCode = error.code;
    // eslint-disable-next-line no-multi-assign
    tags.statusText = error.statusText = error.message;
  }

  logger.error(error.message, tags);
}

/**
 * @param {Error} error
 * @param {import('../types/index').NordicRequestConfig} [requestConfig]
 * @param {import('../types/index').RestClientConfig} [instanceConfig]
 */
const logErrorIfApply = (error, requestConfig = {}, instanceConfig = {}) => {
  if (requestConfig.logErrors ?? instanceConfig.logErrors ?? true) {
    logError(error);
  }
};

module.exports = { logger, logErrorIfApply };
